import React, { useState } from "react";
import API from "../api"; // Axios instance

const AIAdvice = () => {
    const [mood, setMood] = useState("");
    const [stress, setStress] = useState("");
    const [adviceList, setAdviceList] = useState([]); // store all advice

    const getAdvice = async () => {
        if (!mood && !stress) return;

        try {
            const response = await API.post("ai-advice/", {
                mood: mood,
                stress: stress,
            });

            // Add new advice to the list
            setAdviceList((prev) => [
                ...prev,
                { mood, stress, advice: response.data.advice },
            ]);

            // Clear inputs
            setMood("");
            setStress("");
        } catch (error) {
            console.error(error);
            setAdviceList((prev) => [
                ...prev,
                { mood, stress, advice: "Error fetching advice. Please try again." },
            ]);
        }
    };

    return (
        <div>
            <h2>AI Mental Health Assistant</h2>
            <input
                type="text"
                placeholder="Enter your mood"
                value={mood}
                onChange={(e) => setMood(e.target.value)}
            />
            <input
                type="text"
                placeholder="Enter your stress/anxiety"
                value={stress}
                onChange={(e) => setStress(e.target.value)}
            />
            <button onClick={getAdvice}>Get Advice</button>

            {adviceList.length > 0 && (
                <div>
                    <h3>AI Advice History:</h3>
                    <ul>
                        {adviceList.map((item, index) => (
                            <li key={index}>
                                <strong>Mood:</strong> {item.mood} | <strong>Stress:</strong>{" "}
                                {item.stress} <br />
                                <strong>Advice:</strong> {item.advice}
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>
    );
};

export default AIAdvice;
